import{_ as n,o as i,c as a,ag as r}from"./chunks/framework.BZohXCq9.js";const u=JSON.parse('{"title":"04 — Lộ trình phát hành (Roadmap)","description":"","frontmatter":{},"headers":[],"relativePath":"00-san-pham/04-lo-trinh-phat-hanh.md","filePath":"00-san-pham/04-lo-trinh-phat-hanh.md"}'),h={name:"00-san-pham/04-lo-trinh-phat-hanh.md"};function o(e,t,d,s,l,c){return i(),a("div",null,[...t[0]||(t[0]=[r(`<h1 id="_04-—-lo-trinh-phat-hanh-roadmap" tabindex="-1">04 — Lộ trình phát hành (Roadmap) <a class="header-anchor" href="#_04-—-lo-trinh-phat-hanh-roadmap" aria-label="Permalink to &quot;04 — Lộ trình phát hành (Roadmap)&quot;">​</a></h1><blockquote><p><strong>Vai trò đọc</strong>: PO, PM, Scrum Master, Founder — biết &quot;đang ở đâu trong timeline, sắp tới làm gì&quot;. <strong>Cập nhật</strong>: PM update sau mỗi sprint retro. Mọi pivot scope/sequence phải log vào <code>99-tham-khao/changelog.md</code>.</p></blockquote><hr><h2 id="roadmap-tong-3-phase-18-thang" tabindex="-1">Roadmap tổng (3 phase, 18 tháng) <a class="header-anchor" href="#roadmap-tong-3-phase-18-thang" aria-label="Permalink to &quot;Roadmap tổng (3 phase, 18 tháng)&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>2026 ────────────────────────────────────────────────────► 2027 ───►  2028+</span></span>
<span class="line"><span> Q2          Q3            Q4              2027 Q1-Q2     Q3-Q4</span></span>
<span class="line"><span> │           │             │               │              │</span></span>
<span class="line"><span> │ Phase 1   │ Phase 1     │ Phase 1.5     │ Phase 2      │ Phase 3+</span></span>
<span class="line"><span> │ MVP build │ MVP launch  │ EN + loyalty  │ Affiliate +  │ Hotel portal</span></span>
<span class="line"><span> │           │ (beta)      │ + upsell      │ Mobile RN    │ lite, đa thị trường</span></span>
<span class="line"><span> ▼           ▼             ▼               ▼              ▼</span></span></code></pre></div><h3 id="phase-1-—-mvp-q2-q3-2026-3-6-thang" tabindex="-1">Phase 1 — MVP (Q2-Q3/2026, 3-6 tháng) <a class="header-anchor" href="#phase-1-—-mvp-q2-q3-2026-3-6-thang" aria-label="Permalink to &quot;Phase 1 — MVP (Q2-Q3/2026, 3-6 tháng)&quot;">​</a></h3><p><strong>Mục tiêu</strong>: Launch private beta tour operator B2C cho thị trường VN — book Series Tour online + lead capture Private Tour, có CMS đủ vận hành, SEO foundation, dashboard L0.</p><p><strong>Definition of Success</strong>:</p><ul><li>≥20 tour active trên web (Founder ký contract trước)</li><li>Booking flow happy-path không lỗi với 3 user thật private beta</li><li>SEO: sitemap động + 100% page có metadata + structured data</li><li>Admin tạo 1 tour mới &lt;5 phút (không cần dev support)</li><li>Tháng 6 sau launch đạt ≥50 booking/tháng (target — có thể điều chỉnh)</li></ul><h3 id="phase-1-5-—-hoan-thien-en-q4-2026" tabindex="-1">Phase 1.5 — Hoàn thiện &amp; EN (Q4/2026) <a class="header-anchor" href="#phase-1-5-—-hoan-thien-en-q4-2026" aria-label="Permalink to &quot;Phase 1.5 — Hoàn thiện &amp; EN (Q4/2026)&quot;">​</a></h3><p><strong>Mục tiêu</strong>: Mở rộng audience + tăng AOV + chuẩn bị traffic Phase 2.</p><table tabindex="0"><thead><tr><th>Module</th><th>Lý do</th></tr></thead><tbody><tr><td>EN landing + content tour quốc tế</td><td>Khách quốc tế ghé VN tăng → mở luồng EN</td></tr><tr><td>Loyalty cơ bản (point + voucher)</td><td>Repeat rate &gt;20% → ROI cao hơn acquire mới</td></tr><tr><td>Upsell (bảo hiểm, room upgrade, sân bay riêng)</td><td>Tăng AOV 15-25% không cần thêm tour</td></tr><tr><td>Self-service cancel theo policy</td><td>Giảm load support</td></tr><tr><td>Admin Dashboard L1 (conversion, AOV, retention)</td><td>Đo lường hiệu quả marketing</td></tr></tbody></table><h3 id="phase-2-—-scale-2027" tabindex="-1">Phase 2 — Scale (2027) <a class="header-anchor" href="#phase-2-—-scale-2027" aria-label="Permalink to &quot;Phase 2 — Scale (2027)&quot;">​</a></h3><p><strong>Mục tiêu</strong>: Tăng acquisition channel + chuyển mobile.</p><table tabindex="0"><thead><tr><th>Module</th><th>Lý do</th></tr></thead><tbody><tr><td>Affiliate / KOL referral</td><td>Acquire mới qua người nổi tiếng — không marketplace</td></tr><tr><td>Mobile app (React Native)</td><td>Khi web mobile đã chứng minh retention</td></tr><tr><td>Inventory tinh chỉnh (per-date allotment tracking)</td><td>Khi volume đủ để vận hành chi tiết hơn</td></tr><tr><td>Admin Dashboard L2 (P&amp;L tour, profit/tour)</td><td>Khi accounting đã ổn định</td></tr></tbody></table><h3 id="phase-3-—-mo-rong-2028" tabindex="-1">Phase 3+ — Mở rộng (2028+) <a class="header-anchor" href="#phase-3-—-mo-rong-2028" aria-label="Permalink to &quot;Phase 3+ — Mở rộng (2028+)&quot;">​</a></h3><ul><li>Hotel portal lite (vẫn không OTA — chỉ partner self-update info)</li><li>Đa thị trường (CN/JP nếu data ủng hộ)</li><li>Multi-tenant admin nếu acquire công ty khác</li><li><strong>Chưa committed</strong> — phụ thuộc Phase 1+2 outcome.</li></ul><hr><h2 id="sprint-roadmap-phase-1" tabindex="-1">Sprint roadmap Phase 1 <a class="header-anchor" href="#sprint-roadmap-phase-1" aria-label="Permalink to &quot;Sprint roadmap Phase 1&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SPRINT 1 ──► SPRINT 2 ──► SPRINT 3 ──► SPRINT 4 ──► SPRINT 5 ──► SPRINT 6</span></span>
<span class="line"><span>Foundation  CMS         Discovery    Booking      Member       Optimize</span></span>
<span class="line"><span>(Done)      (Done)      (Doing)      (Upcoming)   (Upcoming)   (Upcoming)</span></span></code></pre></div><h3 id="tang-1-—-foundation-sprint-1-2-done" tabindex="-1">Tầng 1 — Foundation (Sprint 1-2, Done) <a class="header-anchor" href="#tang-1-—-foundation-sprint-1-2-done" aria-label="Permalink to &quot;Tầng 1 — Foundation (Sprint 1-2, Done)&quot;">​</a></h3><p><strong>Sprint 1 — Nền tảng &amp; Hạ tầng</strong> ✅</p><ul><li>Mono-repo (Web + App + Doc)</li><li>Prisma + Supabase Auth + middleware admin/public</li><li>Service layer convention</li></ul><p>→ Chi tiết: <code>../05-quan-ly-sprint/sprint-1-nen-tang.md</code></p><p><strong>Sprint 2 — Quản trị Nội dung &amp; Điểm đến</strong> ✅</p><ul><li>CRUD destination / tour / hotel / room / region</li><li>Cloudinary upload + image management</li><li>Audit log (<code>ActivityLog</code>)</li></ul><p>→ Chi tiết: <code>../05-quan-ly-sprint/sprint-2-quan-tri-diem-den/</code></p><h3 id="tang-2-—-đoi-nen-schema-tao-doanh-thu-sprint-3-→-6" tabindex="-1">Tầng 2 — Đổi nền schema + Tạo doanh thu (Sprint 3 → 6) <a class="header-anchor" href="#tang-2-—-đoi-nen-schema-tao-doanh-thu-sprint-3-→-6" aria-label="Permalink to &quot;Tầng 2 — Đổi nền schema + Tạo doanh thu (Sprint 3 → 6)&quot;">​</a></h3><p><strong>Sprint 3 — Khám phá &amp; Tìm kiếm</strong> 🔶 Tạm dừng (~40%)</p><ul><li>Trang danh sách tour + lọc cơ bản đã có</li><li>Gợi ý từ khoá, lọc theo đánh giá, bản đồ gom điểm → đẩy sang <strong>Sprint 5</strong> (sau khi đổi nền schema)</li><li>Đã hỗ trợ trang chạy server (SSR/ISR) + bộ nhớ đệm</li></ul><p>→ Chi tiết: <code>../05-quan-ly-sprint/sprint-3-tim-kiem-kham-pha/</code></p><p><strong>Sprint 4 — Đổi nền Schema (Schema Pivot)</strong> 🔥 ĐANG LÀM (2 tuần)</p><ul><li>Sprint chỉnh lại toàn bộ cấu trúc dữ liệu cho khớp các quyết định kiến trúc ADR-001..006 (Khách sạn = nội dung tham chiếu, Bảng giá theo đầu khách, ID kiểu UUID, Form yêu cầu tour riêng)</li><li>Chạy migration <code>add_pricing_options_and_allotment</code> (10 phần)</li><li>Chỉnh lại CRUD Tour + Service đặt chỗ + Widget đặt nhiều khách</li><li>Lý do tồn tại: nếu đi thẳng Sprint 6 (Đặt chỗ) với cấu trúc dữ liệu cũ → chắc chắn phải làm lại</li></ul><p>→ Chi tiết: <code>../05-quan-ly-sprint/sprint-4-schema-pivot/</code></p><p><strong>Sprint 5 — Đóng nốt Tìm kiếm</strong> ⏳ Sắp tới (1.5 tuần)</p><ul><li>Làm tiếp 60% Sprint 3 còn dở</li><li>Gợi ý từ khoá, lọc theo đánh giá / loại tour, bản đồ gom điểm</li></ul><p>→ Chi tiết: <code>../05-quan-ly-sprint/sprint-5-dong-tim-kiem/</code></p><p><strong>Sprint 6 — Đặt chỗ &amp; Thanh toán</strong> ⏳ Sắp tới (3 tuần)</p><ul><li><strong>Sprint quan trọng nhất Phase 1</strong> — sinh doanh thu</li><li>Luồng đặt: chọn ngày → form khách → thanh toán → xác nhận (đã chỉnh xong cấu trúc ở Sprint 4)</li><li>Khoá hàng đợi <code>TourDeparture.bookedCount</code> để tránh đặt trùng (đã có sẵn từ Sprint 4)</li><li>Tích hợp VNPay + MoMo</li><li>Form yêu cầu tour riêng <code>InquiryRequest</code> (đã làm ở Sprint 4)</li><li>Tự động huỷ đặt chỗ chưa thanh toán quá 15 phút (job định kỳ)</li><li>Email gửi xác nhận (Resend)</li></ul><p><strong>Điều kiện cần trước</strong> (Sprint 4 đã đảm bảo):</p><ol><li>✅ Migration <code>add_pricing_options_and_allotment</code> (Sprint 4 task S4-01)</li><li>✅ Toàn bộ ID/khoá ngoại đã chuyển sang UUID (ADR-003) — Sprint 4 task S4-01</li><li>✅ Khoá ngoại <code>Booking.userId</code> + <code>Review.userId</code> đổi sang <code>onDelete: Restrict</code> để không xoá nhầm (Sprint 4)</li><li>✅ Bảng giá theo đầu khách đã sống (Sprint 4 task S4-03/04/05)</li><li>✅ Tài liệu <code>03-co-so-du-lieu/03-toan-ven-concurrency.md</code> đã chốt</li></ol><p>→ Chi tiết: <code>../05-quan-ly-sprint/sprint-6-dat-cho-thanh-toan/</code></p><h3 id="tang-3-—-giu-chan-khach-ra-mat-sprint-7-8" tabindex="-1">Tầng 3 — Giữ chân khách &amp; Ra mắt (Sprint 7-8) <a class="header-anchor" href="#tang-3-—-giu-chan-khach-ra-mat-sprint-7-8" aria-label="Permalink to &quot;Tầng 3 — Giữ chân khách &amp; Ra mắt (Sprint 7-8)&quot;">​</a></h3><p><strong>Sprint 7 — Đánh giá khách</strong> ⏳ (1.5 tuần)</p><ul><li>Đánh giá đã xác minh (chỉ user đã đặt tour <code>COMPLETED</code> mới đánh giá được)</li><li>Admin duyệt / từ chối đánh giá</li><li>Hiển thị đánh giá trên trang chi tiết tour + đánh dấu Schema.org <code>aggregateRating</code> để Google hiểu</li><li>Trang cá nhân <code>/tai-khoan/*</code> + đơn của tôi <code>/don-dat/*</code></li></ul><blockquote><p><s>Tích điểm thành viên</s> — hoãn sang Phase 2.</p></blockquote><p>→ Chi tiết: <code>../05-quan-ly-sprint/sprint-7-danh-gia/</code></p><p><strong>Sprint 8 — Báo cáo + SEO + Ra mắt</strong> ⏳ (2 tuần)</p><ul><li>Bảng tổng quan vận hành L0 (đơn hôm nay, doanh thu tuần, tour bán chạy, xuất CSV — xem ADR-007)</li><li>Hoàn thiện SEO (Lighthouse &gt;90, Core Web Vitals, ảnh chia sẻ mạng xã hội, Schema.org đầy đủ)</li><li>Tối ưu hiệu năng + tinh chỉnh bộ nhớ đệm</li><li>Danh sách kiểm tra trước khi ra mắt (tên miền, SSL, theo dõi, sao lưu, thông báo fanpage)</li></ul><p>→ Chi tiết: <code>../05-quan-ly-sprint/sprint-8-quy-hoach-toi-uu/</code></p><hr><h2 id="vi-sao-theo-thu-tu-nay" tabindex="-1">Vì sao theo thứ tự này <a class="header-anchor" href="#vi-sao-theo-thu-tu-nay" aria-label="Permalink to &quot;Vì sao theo thứ tự này&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Quyết định</th><th>Lý do</th></tr></thead><tbody><tr><td><strong>Sprint 4 Đổi nền trước Sprint 6 Đặt chỗ</strong></td><td>Cấu trúc dữ liệu cũ lệch ADR-001..006 ở 7 chỗ. Đi thẳng Sprint 6 với cấu trúc cũ chắc chắn phải làm lại. Đổi nền 2 tuần để cứu được 4-6 tuần làm lại</td></tr><tr><td><strong>Sprint 5 Đóng tìm kiếm sau Đổi nền</strong></td><td>Sprint 3 đã tạm dừng ở 40%. Sprint 5 dùng cấu trúc dữ liệu mới (bảng giá theo đầu khách, loại tour kiểu enum) cho lọc đánh giá + gợi ý</td></tr><tr><td><strong>Đặt chỗ trước Đánh giá</strong> (Sprint 6 trước Sprint 7)</td><td>Sinh doanh thu. Đánh giá tuy có cấu trúc dữ liệu sẵn nhưng UI có thể hoãn 1 sprint mà không chặn ra mắt</td></tr><tr><td><strong>CMS trước Khám phá</strong></td><td>Admin cần tạo tour để có dữ liệu hiển thị; Sprint 3 dùng dữ liệu của Sprint 2</td></tr><tr><td><strong>SEO ở Sprint 8, không phải Sprint 1</strong></td><td>Nền tảng SEO (thẻ meta, sitemap) đã có từ Sprint 1; tối ưu Lighthouse để Sprint 8 khi đã có đủ dữ liệu</td></tr><tr><td><strong>Tối ưu cuối cùng</strong></td><td>Đo hiệu năng cần dữ liệu giống thật → chạy trên dữ liệu thật</td></tr><tr><td><strong>Form yêu cầu tour riêng gộp vào Sprint 4 Đổi nền</strong></td><td>Cùng đụng tới đặt chỗ + email + thông báo admin — gộp tránh trùng việc</td></tr><tr><td><strong>Hoãn Tích điểm thành viên</strong></td><td>Khách Việt giai đoạn đầu ít quan tâm thẻ thành viên du lịch. Làm sau khi có 100-200 khách thật</td></tr></tbody></table><hr><h2 id="moc-san-pham-ban-giao" tabindex="-1">Mốc &amp; Sản phẩm bàn giao <a class="header-anchor" href="#moc-san-pham-ban-giao" aria-label="Permalink to &quot;Mốc &amp; Sản phẩm bàn giao&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tháng</th><th>Mốc</th><th>Sản phẩm</th></tr></thead><tbody><tr><td><strong>M1</strong> (now)</td><td>Sprint 4 Đổi nền xong</td><td>Cấu trúc dữ liệu UUID + 10 phần migration đã chạy + Bảng giá theo đầu khách đã sống + Form yêu cầu tour riêng đã sống</td></tr><tr><td><strong>M2</strong></td><td>Sprint 5 đóng</td><td>Gợi ý từ khoá + lọc theo đánh giá + bản đồ gom điểm</td></tr><tr><td><strong>M3</strong></td><td>Sprint 6 đóng</td><td>Luồng đặt tour đầu cuối + 3 user thử + VNPay + email</td></tr><tr><td><strong>M4</strong></td><td>Sprint 7 đóng</td><td>Đánh giá đã xác minh đi vào hoạt động, trang cá nhân</td></tr><tr><td><strong>M5</strong></td><td>Sprint 8 đóng</td><td>Lighthouse &gt;90, Bảng tổng quan vận hành L0, danh sách kiểm tra trước ra mắt</td></tr><tr><td><strong>M6</strong></td><td><strong>Ra mắt nội bộ (private beta)</strong></td><td>20 tour + 3-5 user thật + Founder go-live</td></tr></tbody></table><hr><h2 id="rui-ro-ve-tien-đo" tabindex="-1">Rủi ro về tiến độ <a class="header-anchor" href="#rui-ro-ve-tien-đo" aria-label="Permalink to &quot;Rủi ro về tiến độ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Rủi ro</th><th>Tác động</th><th>Cách phòng ngừa</th></tr></thead><tbody><tr><td>Migration <code>add_pricing_options_and_allotment</code> hỏng phải khôi phục</td><td>Chặn Sprint 6 → mất 1-2 tuần</td><td>Test trên Supabase staging với bản dump prod trước, chạy script kiểm tra trước khi áp dụng, có sao lưu PITR</td></tr><tr><td>VNPay/MoMo sandbox không ổn định</td><td>Chặn nghiệm thu Sprint 6</td><td>Dùng sandbox sớm cuối Sprint 5, có phương án giả lập dự phòng</td></tr><tr><td>Lượng truy cập SEO không lên đúng kỳ vọng</td><td>Phase 1.5 lùi</td><td>Dồn ngân sách quảng cáo bù 6-12 tháng đầu</td></tr><tr><td>Hotel partner không đủ 20 tour</td><td>Phase 1 launch trì hoãn</td><td>Founder track contract weekly, có buffer 30%</td></tr><tr><td>Team scale: 2 dev không kịp</td><td>Sprint trễ 2-3 tuần</td><td>Đã chấp nhận trade-off scope, không scope creep</td></tr></tbody></table><hr><h2 id="build-vs-buy-—-quyet-đinh-phase-1" tabindex="-1">Build vs Buy — quyết định Phase 1 <a class="header-anchor" href="#build-vs-buy-—-quyet-đinh-phase-1" aria-label="Permalink to &quot;Build vs Buy — quyết định Phase 1&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Module</th><th>Build / Buy</th><th>Lý do</th></tr></thead><tbody><tr><td>Auth</td><td><strong>Buy</strong> (Supabase Auth)</td><td>Free tier đủ, không build custom — security risk</td></tr><tr><td>Payment</td><td><strong>Buy</strong> (VNPay + MoMo SDK)</td><td>Bắt buộc — không có lựa chọn build</td></tr><tr><td>Email transactional</td><td><strong>Buy</strong> (Resend)</td><td>Free tier 3k/tháng đủ phase 1</td></tr><tr><td>Image hosting</td><td><strong>Buy</strong> (Cloudinary)</td><td>Free tier đủ, optimize tự động</td></tr><tr><td>Analytics</td><td><strong>Buy</strong> (PostHog free / Plausible)</td><td>Build từ 0 mất 2-3 sprint</td></tr><tr><td>Search</td><td><strong>Build</strong> (Postgres full-text)</td><td>Phase 1 chưa cần Algolia/Meilisearch — Postgres đủ với &lt;1k tour</td></tr><tr><td>CMS</td><td><strong>Build</strong> (Next.js admin portal)</td><td>Off-the-shelf CMS không hợp model tour</td></tr><tr><td>Dashboard L0</td><td><strong>Build</strong></td><td>Đơn giản, query Prisma + render. L1/L2 sau cân nhắc buy</td></tr></tbody></table><hr><h2 id="resource-phase-1" tabindex="-1">Resource Phase 1 <a class="header-anchor" href="#resource-phase-1" aria-label="Permalink to &quot;Resource Phase 1&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Vai trò</th><th>FTE</th><th>Trách nhiệm</th></tr></thead><tbody><tr><td>Founder</td><td>1.0</td><td>Vision, contract hotel/partner, sales, GTM</td></tr><tr><td>Tech Lead / Senior Dev</td><td>1.0</td><td>Architecture, DB, code review, mentor</td></tr><tr><td>Dev (mid/junior)</td><td>1-2</td><td>Feature implementation theo sprint</td></tr><tr><td>Content / Ops (part-time)</td><td>0.5</td><td>Upload tour, viết SEO content, hỗ trợ khách</td></tr><tr><td>Designer (freelance)</td><td>0.2</td><td>UI Figma + component spec</td></tr></tbody></table><p><strong>Tổng</strong>: 3-5 FTE Phase 1. Phase 1.5 cân nhắc thêm 1 marketer + 1 customer support.</p><hr><h2 id="lien-ket" tabindex="-1">Liên kết <a class="header-anchor" href="#lien-ket" aria-label="Permalink to &quot;Liên kết&quot;">​</a></h2><ul><li>Vision: <code>01-tam-nhin.md</code></li><li>Mô hình kinh doanh: <code>02-mo-hinh-kinh-doanh.md</code></li><li>Personas: <code>03-personas-user-journey.md</code></li><li>Sprint folders: <code>../05-quan-ly-sprint/</code></li><li>Trạng thái triển khai web: <code>../05-quan-ly-sprint/trang-thai-web.md</code></li><li>Backlog chi tiết: <code>../05-quan-ly-sprint/backlog-chi-tiet.md</code></li></ul>`,69)])])}const g=n(h,[["render",o]]);export{u as __pageData,g as default};
